using namespace std;

class Solution {
public:
    string resultingString(string s) {
        stack<char> stk;
        for (char c : s) {
            if (!stk.empty()) {
                char top = stk.top();
                if ((abs(c - top) == 1) || (c == 'a' && top == 'z') || (c == 'z' && top == 'a')) {
                    stk.pop();
                    continue;
                }
            }
            stk.push(c);
        }
        string result;
        while (!stk.empty()) {
            result += stk.top();
            stk.pop();
        }
        reverse(result.begin(), result.end());
        return result;
    }
};

